vertexWgsl:
varying color: vec4f;
varying worldPosition: vec3f;
varying clipDepth: f32;
varying normalView: vec3f;
varying shapeFlag: f32;

uniform matrix_view: mat4x4f;
uniform matrix_viewProjection: mat4x4f;
uniform particlePixelScale: f32;
uniform viewportSize: vec2f;
uniform screenViewportSize: vec2f;
uniform motionMode: f32;
uniform emitterPos: vec3f;
uniform hairLength: f32;
uniform hairGrowth: f32;
uniform hairRandomTilt: f32;
uniform stretchAlongMotion: f32;
uniform rotationStartMin: f32;
uniform rotationStartMax: f32;
uniform rotationEndMin: f32;
uniform rotationEndMax: f32;
uniform rotationRandom: f32;
uniform rotationEasing: f32;
uniform particleShape: f32;
uniform shapeSize: vec3f;

var<storage, read> particles: array<Particle>;
var<storage, read> pathData: PathStorage;
var<storage, read> drawOrder: array<u32>;

var<private> corners: array<vec2f, 4> = array<vec2f, 4>(
    vec2f(-1.0,  1.0), vec2f(1.0,  1.0),
    vec2f(-1.0, -1.0), vec2f(1.0, -1.0),
);

@vertex
fn vertexMain(input: VertexInput) -> VertexOutput {
    let shape = i32(uniform.particleShape + 0.5);
    let vertsPer = shapeVertCount(shape);
    let drawSlot = input.vertexIndex / vertsPer;
    let localIdx = input.vertexIndex % vertsPer;
    let particleIndex = drawOrder[drawSlot];
    let p = particles[particleIndex];
    var output: VertexOutput;

    if (p.life <= 0.0) {
        output.position = vec4f(2.0, 2.0, 2.0, 1.0);
        output.color = vec4f(0.0);
        output.normalView = vec3f(0.0, 0.0, 1.0);
        output.shapeFlag = 0.0;
        return output;
    }

    let lifeT = particleLifeT(p.life, p.maxLife);
    let rnd = renderRand1(p.seed);
    let rot = renderCurveScalar(
        uniform.rotationStartMin,
        uniform.rotationStartMax,
        uniform.rotationEndMin,
        uniform.rotationEndMax,
        rnd,
        uniform.rotationRandom,
        lifeT,
        uniform.rotationEasing,
    );

    let useHair = abs(uniform.motionMode - 3.0) < 0.5;
    let useMesh = shape > 0 && !useHair;

    var clipPos: vec4f;
    var worldPos = p.position;
    var fragCorner = vec2f(0.0);
    var viewNormal = vec3f(0.0, 0.0, 1.0);

    if (useMesh) {
        var localPos = shapeLocalPosition(shape, localIdx);
        var localNorm = shapeLocalNormal(shape, localIdx);
        let scale = shapeScaleFor(shape, uniform.shapeSize * p.size);
        localPos = localPos * scale;
        localNorm = normalize(localNorm / scale);
        localPos = rotateY3(localPos, rot);
        localNorm = rotateY3(localNorm, rot);
        worldPos = p.position + localPos;
        viewNormal = (uniform.matrix_view * vec4f(localNorm, 0.0)).xyz;
        clipPos = uniform.matrix_viewProjection * vec4f(worldPos, 1.0);
    } else {
        var corner = corners[localIdx];
        if (abs(rot) > 0.0001) {
            let cs = cos(rot);
            let sn = sin(rot);
            corner = vec2f(corner.x * cs - corner.y * sn, corner.x * sn + corner.y * cs);
        }

        var clipCorner = corner;
        fragCorner = corner;

#ifndef SHADOW_PASS
        if (uniform.stretchAlongMotion > 0.001 && !useHair) {
            var motion = p.velocity;
            if (abs(uniform.motionMode - 1.0) < 0.5) {
                motion = renderSamplePathTangent(lifeT);
            }
            let viewMotion = (uniform.matrix_view * vec4f(motion, 0.0)).xyz;
            let motion2 = vec2f(viewMotion.x, viewMotion.y);
            let speed = length(motion);
            if (length(motion2) > 0.0001) {
                let angle = atan2(motion2.y, motion2.x);
                let cs = cos(angle);
                let sn = sin(angle);
                var lx = clipCorner.x * cs + clipCorner.y * sn;
                let ly = -clipCorner.x * sn + clipCorner.y * cs;
                lx *= 1.0 + uniform.stretchAlongMotion * speed;
                clipCorner = vec2f(lx * cs - ly * sn, lx * sn + ly * cs);
            }
        }
#endif

        if (useHair) {
            worldPos = hairStrandPosition(
                p,
                uniform.emitterPos,
                uniform.hairLength,
                uniform.hairGrowth,
                uniform.hairRandomTilt,
                corner.y,
                corner.x,
            );
        }

#ifdef SHADOW_PASS
        if (useHair) {
            clipPos = uniform.matrix_viewProjection * vec4f(worldPos, 1.0);
        } else {
            let worldHalf = max(
                p.size * uniform.particlePixelScale / max(uniform.screenViewportSize.y, 1.0),
                0.0001,
            );
            let right = normalize(uniform.matrix_view[0].xyz);
            let up = normalize(uniform.matrix_view[1].xyz);
            let clipC = uniform.matrix_viewProjection * vec4f(p.position, 1.0);
            let clipR = uniform.matrix_viewProjection * vec4f(p.position + right * worldHalf, 1.0);
            let clipU = uniform.matrix_viewProjection * vec4f(p.position + up * worldHalf, 1.0);
            clipPos = clipC + corner.x * (clipR - clipC) + corner.y * (clipU - clipC);
        }
#else
        if (useHair) {
            clipPos = uniform.matrix_viewProjection * vec4f(worldPos, 1.0);
        } else {
            let viewPos = uniform.matrix_view * vec4f(p.position, 1.0);
            clipPos = uniform.matrix_viewProjection * vec4f(p.position, 1.0);
            let depth = max(-viewPos.z, 0.001);
            let pixelDiameter = p.size * uniform.particlePixelScale / depth;
            let clipExpand = vec2f(
                clipCorner.x * pixelDiameter / uniform.viewportSize.x,
                clipCorner.y * pixelDiameter / uniform.viewportSize.y,
            ) * clipPos.w;
            clipPos = vec4f(clipPos.xy + clipExpand, clipPos.zw);
        }
#endif
    }

    output.position = clipPos;
    output.color = vec4f(fragCorner.x, fragCorner.y, p.opacity, f32(particleIndex));
    output.worldPosition = worldPos;
    output.clipDepth = clipPos.z / max(abs(clipPos.w), 1e-6);
    output.normalView = viewNormal;
    output.shapeFlag = select(0.0, 1.0, useMesh);
    return output;
}

