#else
var sceneLight0ShadowMap: texture_depth_2d;
var sceneLight0ShadowMapSampler: sampler_comparison;
var sceneLight1ShadowMap: texture_depth_2d;
var sceneLight1ShadowMapSampler: sampler_comparison;
var sceneLight2ShadowMap: texture_depth_2d;
var sceneLight2ShadowMapSampler: sampler_comparison;
var sceneLight3ShadowMap: texture_depth_2d;
var sceneLight3ShadowMapSampler: sampler_comparison;
#endif

uniform sceneLight0CastShadow: f32;
