uniform sceneLight0ShadowParams: vec4f;
uniform sceneLight1CastShadow: f32;
uniform sceneLight1ShadowMatrix: mat4x4f;
uniform sceneLight1ShadowParams: vec4f;
uniform sceneLight2CastShadow: f32;
uniform sceneLight2ShadowMatrix: mat4x4f;
uniform sceneLight2ShadowParams: vec4f;
uniform sceneLight3CastShadow: f32;
uniform sceneLight3ShadowMatrix: mat4x4f;
uniform sceneLight3ShadowParams: vec4f;

var<storage, read> particles: array<Particle>;
var colorMap: texture_2d<f32>;
var colorMapSampler: sampler;
var uSceneDepthMap: texture_2d<uff>;
var uSceneDepthMapSampler: sampler;

fn toViewDir(worldDir: vec3f) -> vec3f {
    let dir = (uniform.matrix_view * vec4f(worldDir, 0.0)).xyz;
    let len = length(dir);
    if (len < 0.0001) {
        return vec3f(0.0, 0.0, 1.0);
    }
    return dir / len;
}

fn viewNormalToWorld(normalView: vec3f) -> vec3f {
    let m = uniform.matrix_view;
    let world = vec3f(
        m[0].x * normalView.x + m[1].x * normalView.y + m[2].x * normalView.z,
        m[0].y * normalView.x + m[1].y * normalView.y + m[2].y * normalView.z,
        m[0].z * normalView.x + m[1].z * normalView.y + m[2].z * normalView.z,
    );
    let len = length(world);
    if (len < 0.0001) {
        return vec3f(0.0, 1.0, 0.0);
    }
    return world / len;
}

fn halfLambert(ndl: f32) -> f32 {
    return ndl * 0.5 + 0.5;
}

fn evalDirLight(normalWorld: vec3f, lightDirWorld: vec3f, lightColor: vec3f) -> vec3f {
    let lightDir = normalize(-lightDirWorld);
    let ndl = halfLambert(max(dot(normalWorld, lightDir), 0.0));
    return lightColor * ndl;
}

fn evalPointLight(normalWorld: vec3f, worldPos: vec3f, lightPosWorld: vec3f, lightColor: vec3f, range: f32) -> vec3f {
    let toLightWorld = lightPosWorld - worldPos;
    let dist = length(toLightWorld);
    if (range <= 0.0001 || dist > range) {
        return vec3f(0.0);
    }
    let atten = 1.0 - smoothstep(range * 0.75, range, dist);
    let toLight = normalize(toLightWorld);
    let ndl = halfLambert(max(dot(normalWorld, toLight), 0.0));
    return lightColor * ndl * atten;
}

fn evalSpotLight(
    normalWorld: vec3f,
    worldPos: vec3f,
    lightPosWorld: vec3f,
    lightDirWorld: vec3f,
    lightColor: vec3f,
    range: f32,
    spot: vec4f,
) -> vec3f {
    let toLightWorld = lightPosWorld - worldPos;
    let dist = length(toLightWorld);
    if (range <= 0.0001 || dist > range) {
        return vec3f(0.0);
    }
    let toLight = normalize(toLightWorld);
    let spotDir = normalize(-lightDirWorld);
    let cosOuter = cos(spot.y);
    let cosInner = cos(spot.x);
    let cosAngle = dot(toLight, spotDir);
    let cone = smoothstep(cosOuter, cosInner, cosAngle);
    if (cone <= 0.0001) {
        return vec3f(0.0);
    }
    let atten = (1.0 - smoothstep(range * 0.75, range, dist)) * cone;
    let ndl = halfLambert(max(dot(normalWorld, toLight), 0.0));
    return lightColor * ndl * atten;
}

fn shadowCoordDirectional(shadowMatrix: mat4x4f, shadowParams: vec4f, worldPos: vec3f, normalWorld: vec3f) -> vec3f {
    let surfacePosition = worldPos + normalWorld * shadowParams.y;
    let projPos = shadowMatrix * vec4f(surfacePosition, 1.0);
    let ndc = projPos.xyz / max(abs(projPos.w), 1e-6);
#ifdef SHADOW_MAP_FLOAT
    // PCSS R32F stores clip depth (litShadowMain input.position.z); compare in the same space.
    return vec3f(ndc.xy, saturate(ndc.z) - 0.0001);
#else
    return ndc;
#endif
}

fn shadowCoordSpot(
    shadowMatrix: mat4x4f,
    shadowParams: vec4f,
    worldPos: vec3f,
    normalWorld: vec3f,
    lightPos: vec3f,
) -> vec3f {
    let toLight = lightPos - worldPos;
    let distScale = length(toLight);
    let surfacePosition = worldPos + normalWorld * shadowParams.y * clamp(1.0 - dot(normalWorld, normalize(toLight)), 0.0, 1.0) * distScale;
    let pos = shadowMatrix * vec4f(surfacePosition, 1.0);
    let xy = pos.xy / pos.w;
    let z = length(toLight) * shadowParams.w + shadowParams.z;
    return vec3f(xy, z);
}

#ifdef SHADOW_MAP_FLOAT
fn sampleShadowMapFloat(shadowMap: texture_2d<f32>, coord: vec3f, resolution: f32) -> f32 {
    if (coord.x < 0.0 || coord.x > 1.0 || coord.y < 0.0 || coord.y > 1.0) {
        return 1.0;
    }
    let mapSize = textureDimensions(shadowMap, 0);
    let res = max(resolution, f32(mapSize.x));
    let uv = coord.xy * res - vec2f(0.5);
    let base = vec2i(i32(floor(uv.x)), i32(floor(uv.y)));
    let maxCoord = vec2i(i32(mapSize.x) - 1, i32(mapSize.y) - 1);
    var sum = 0.0;
    for (var y = -1; y <= 1; y++) {
        for (var x = -1; x <= 1; x++) {
            let tc = clamp(base + vec2i(x, y), vec2i(0), maxCoord);
            let depth = textureLoad(shadowMap, tc, 0).r;
            sum += step(coord.z, depth);
        }
    }
    return sum / 9.0;
}
#else
fn sampleShadowMapDepth(shadowMap: texture_depth_2d, shadowSampler: sampler_comparison, coord: vec3f) -> f32 {
    if (coord.x < 0.0 || coord.x > 1.0 || coord.y < 0.0 || coord.y > 1.0) {
        return 1.0;
    }
    return textureSampleCompareLevel(shadowMap, shadowSampler, coord.xy, coord.z);
}
#endif

fn shadowFactorLight0(lightType: f32, worldPos: vec3f, normalWorld: vec3f, lightPos: vec3f) -> f32 {
    if (uniform.receiveShadow < 0.5 || uniform.sceneLight0CastShadow < 0.5) {
        return 1.0;
    }
    var coord: vec3f;
    if (lightType < 0.5) {
        coord = shadowCoordDirectional(uniform.sceneLight0ShadowMatrix, uniform.sceneLight0ShadowParams, worldPos, normalWorld);
    } else if (lightType < 1.5) {
        return 1.0;
    } else {
        coord = shadowCoordSpot(uniform.sceneLight0ShadowMatrix, uniform.sceneLight0ShadowParams, worldPos, normalWorld, lightPos);
    }
#ifdef SHADOW_MAP_FLOAT
    return sampleShadowMapFloat(sceneLight0ShadowMap, coord, uniform.sceneLight0ShadowParams.x);
#else
    return sampleShadowMapDepth(sceneLight0ShadowMap, sceneLight0ShadowMapSampler, coord);
#endif
}

fn shadowFactorLight1(lightType: f32, worldPos: vec3f, normalWorld: vec3f, lightPos: vec3f) -> f32 {
    if (uniform.receiveShadow < 0.5 || uniform.sceneLight1CastShadow < 0.5) {
        return 1.0;
    }
    var coord: vec3f;
    if (lightType < 0.5) {
        coord = shadowCoordDirectional(uniform.sceneLight1ShadowMatrix, uniform.sceneLight1ShadowParams, worldPos, normalWorld);
    } else if (lightType < 1.5) {
        return 1.0;
    } else {
        coord = shadowCoordSpot(uniform.sceneLight1ShadowMatrix, uniform.sceneLight1ShadowParams, worldPos, normalWorld, lightPos);
    }
#ifdef SHADOW_MAP_FLOAT
    return sampleShadowMapFloat(sceneLight1ShadowMap, coord, uniform.sceneLight1ShadowParams.x);
#else
    return sampleShadowMapDepth(sceneLight1ShadowMap, sceneLight1ShadowMapSampler, coord);
#endif
}

fn shadowFactorLight2(lightType: f32, worldPos: vec3f, normalWorld: vec3f, lightPos: vec3f) -> f32 {
    if (uniform.receiveShadow < 0.5 || uniform.sceneLight2CastShadow < 0.5) {
        return 1.0;
    }
    var coord: vec3f;
    if (lightType < 0.5) {
        coord = shadowCoordDirectional(uniform.sceneLight2ShadowMatrix, uniform.sceneLight2ShadowParams, worldPos, normalWorld);
    } else if (lightType < 1.5) {
        return 1.0;
    } else {
        coord = shadowCoordSpot(uniform.sceneLight2ShadowMatrix, uniform.sceneLight2ShadowParams, worldPos, normalWorld, lightPos);
    }
#ifdef SHADOW_MAP_FLOAT
    return sampleShadowMapFloat(sceneLight2ShadowMap, coord, uniform.sceneLight2ShadowParams.x);
#else
    return sampleShadowMapDepth(sceneLight2ShadowMap, sceneLight2ShadowMapSampler, coord);
#endif
}

fn shadowFactorLight3(lightType: f32, worldPos: vec3f, normalWorld: vec3f, lightPos: vec3f) -> f32 {
    if (uniform.receiveShadow < 0.5 || uniform.sceneLight3CastShadow < 0.5) {
        return 1.0;
    }
    var coord: vec3f;
    if (lightType < 0.5) {
        coord = shadowCoordDirectional(uniform.sceneLight3ShadowMatrix, uniform.sceneLight3ShadowParams, worldPos, normalWorld);
    } else if (lightType < 1.5) {
        return 1.0;
    } else {
        coord = shadowCoordSpot(uniform.sceneLight3ShadowMatrix, uniform.sceneLight3ShadowParams, worldPos, normalWorld, lightPos);
    }
#ifdef SHADOW_MAP_FLOAT
    return sampleShadowMapFloat(sceneLight3ShadowMap, coord, uniform.sceneLight3ShadowParams.x);
#else
    return sampleShadowMapDepth(sceneLight3ShadowMap, sceneLight3ShadowMapSampler, coord);
#endif
}

fn shadowFactorForLight(index: i32, lightType: f32, worldPos: vec3f, normalWorld: vec3f, lightPos: vec3f) -> f32 {
    if (index == 0) { return shadowFactorLight0(lightType, worldPos, normalWorld, lightPos); }
    if (index == 1) { return shadowFactorLight1(lightType, worldPos, normalWorld, lightPos); }
    if (index == 2) { return shadowFactorLight2(lightType, worldPos, normalWorld, lightPos); }
    return shadowFactorLight3(lightType, worldPos, normalWorld, lightPos);
}

fn evalSceneLight(
    lightType: f32,
    lightColor: vec3f,
    lightDirWorld: vec3f,
    lightPosWorld: vec3f,
    lightRange: f32,
    lightSpot: vec4f,
    normalWorld: vec3f,
    worldPos: vec3f,
) -> vec3f {
    if (lightType < 0.0) {
        return vec3f(0.0);
    }
    if (lightType < 0.5) {
        return evalDirLight(normalWorld, lightDirWorld, lightColor);
    }
    if (lightType < 1.5) {
        return evalPointLight(normalWorld, worldPos, lightPosWorld, lightColor, lightRange);
    }
    return evalSpotLight(normalWorld, worldPos, lightPosWorld, lightDirWorld, lightColor, lightRange, lightSpot);
}

fn evalSceneLightShadowed(
    lightIndex: i32,
    lightType: f32,
    lightColor: vec3f,
    lightDirWorld: vec3f,
    lightPosWorld: vec3f,
    lightRange: f32,
    lightSpot: vec4f,
    normalWorld: vec3f,
    worldPos: vec3f,
) -> vec3f {
    let lit = evalSceneLight(lightType, lightColor, lightDirWorld, lightPosWorld, lightRange, lightSpot, normalWorld, worldPos);
    let shadow = shadowFactorForLight(lightIndex, lightType, worldPos, normalWorld, lightPosWorld);
    return lit * shadow;
}

fn combinedShadowVisibility(worldPos: vec3f, shadowNormal: vec3f) -> f32 {
    if (uniform.receiveShadow < 0.5) {
        return 1.0;
    }
    var visibility = 1.0;
    if (uniform.sceneLightCount > 0.0) {
        visibility *= shadowFactorForLight(0, uniform.sceneLight0Type, worldPos, shadowNormal, uniform.sceneLight0Pos);
    }
    if (uniform.sceneLightCount > 1.0) {
        visibility *= shadowFactorForLight(1, uniform.sceneLight1Type, worldPos, shadowNormal, uniform.sceneLight1Pos);
    }
    if (uniform.sceneLightCount > 2.0) {
        visibility *= shadowFactorForLight(2, uniform.sceneLight2Type, worldPos, shadowNormal, uniform.sceneLight2Pos);
    }
    if (uniform.sceneLightCount > 3.0) {
        visibility *= shadowFactorForLight(3, uniform.sceneLight3Type, worldPos, shadowNormal, uniform.sceneLight3Pos);
    }
    return visibility;
}

fn shadowNormalWorld(_normalView: vec3f) -> vec3f {
    return vec3f(0.0, 1.0, 0.0);
}

fn shadowTintFromAmbient(shadowVis: f32) -> vec3f {
    let ambient = max(uniform.sceneAmbient, vec3f(0.02));
    return mix(ambient, vec3f(1.0), shadowVis);
}

fn particleLighting(normalView: vec3f, worldPos: vec3f) -> vec3f {
    let normalWorld = viewNormalToWorld(normalView);
    let shadowNormal = shadowNormalWorld(normalView);
    let shadowVis = combinedShadowVisibility(worldPos, shadowNormal);

    if (uniform.useLighting < 0.5) {
        if (uniform.receiveShadow < 0.5) {
            return vec3f(1.0);
        }
        return shadowTintFromAmbient(shadowVis);
    }

    var lighting = uniform.sceneAmbient;
    if (uniform.sceneLightCount > 0.0) {
        let lit = evalSceneLight(
            uniform.sceneLight0Type,
            uniform.sceneLight0Color,
            uniform.sceneLight0Dir,
            uniform.sceneLight0Pos,
            uniform.sceneLight0Range,
            uniform.sceneLight0Spot,
            normalWorld,
            worldPos,
        );
        lighting += lit * shadowFactorForLight(0, uniform.sceneLight0Type, worldPos, shadowNormal, uniform.sceneLight0Pos);
    }
    if (uniform.sceneLightCount > 1.0) {
        let lit = evalSceneLight(
            uniform.sceneLight1Type,
            uniform.sceneLight1Color,
            uniform.sceneLight1Dir,
            uniform.sceneLight1Pos,
            uniform.sceneLight1Range,
            uniform.sceneLight1Spot,
            normalWorld,
            worldPos,
        );
        let shadow = shadowFactorForLight(1, uniform.sceneLight1Type, worldPos, shadowNormal, uniform.sceneLight1Pos);
        lighting += lit * shadow;
    }
    if (uniform.sceneLightCount > 2.0) {
        let lit = evalSceneLight(
            uniform.sceneLight2Type,
            uniform.sceneLight2Color,
            uniform.sceneLight2Dir,
            uniform.sceneLight2Pos,
            uniform.sceneLight2Range,
            uniform.sceneLight2Spot,
            normalWorld,
            worldPos,
        );
        let shadow = shadowFactorForLight(2, uniform.sceneLight2Type, worldPos, shadowNormal, uniform.sceneLight2Pos);
        lighting += lit * shadow;
    }
    if (uniform.sceneLightCount > 3.0) {
        let lit = evalSceneLight(
            uniform.sceneLight3Type,
            uniform.sceneLight3Color,
            uniform.sceneLight3Dir,
            uniform.sceneLight3Pos,
            uniform.sceneLight3Range,
            uniform.sceneLight3Spot,
            normalWorld,
            worldPos,
        );
        let shadow = shadowFactorForLight(3, uniform.sceneLight3Type, worldPos, shadowNormal, uniform.sceneLight3Pos);
        lighting += lit * shadow;
    }

    let lit = max(lighting, vec3f(0.0));
    let strength = max(uniform.lightIntensity, 0.0);
    var blend = clamp(strength, 0.0, 1.0);
    if (blend < 0.001) {
        blend = 1.0;
    }
    var result = mix(vec3f(1.0), lit, blend);
    if (strength > 1.0) {
        result *= strength;
    }
    return result;
}

fn particleViewDepth(p: Particle) -> f32 {
    let viewPos = uniform.matrix_view * vec4f(p.position, 1.0);
    return max(-viewPos.z, 0.001);
}

fn softenDiscAlphaForDepthWrite(soft: f32, opacity: f32) -> f32 {
    var alpha = opacity * soft;
    if (uniform.depthWrite > 0.5) {
        // Trim the outer fringe that blends with the environment and writes bad depth.
        alpha *= smoothstep(0.0, 0.35, soft);
    }
    return alpha;
}

fn fadeAlphaAgainstSceneDepth(fragPos: vec4f, alpha: f32) -> f32 {
    if (uniform.useSceneDepth < 0.5 || alpha < 0.0001) {
        return alpha;
    }
    let uv = fragPos.xy / max(uniform.screenViewportSize, vec2f(1.0));
    let sceneDepth = textureSampleLevel(uSceneDepthMap, uSceneDepthMapSampler, uv, 0.0).r;
    let depthDiff = sceneDepth - fragPos.z;
    return alpha * clamp(depthDiff * 80.0, 0.0, 1.0);
}

fn discSphereFragDepth(clipDepth: f32, corner: vec2f) -> f32 {
    let r2 = dot(corner, corner);
    let cap = sqrt(max(1.0 - r2, 0.0));
    return clipDepth - cap * 0.02;
}

fn finalizeDiscFragment(
    input: FragmentInput,
    rgb: vec3f,
    soft: f32,
    opacity: f32,
) -> FragmentOutput {
    var output: FragmentOutput;
    var alpha = softenDiscAlphaForDepthWrite(soft, opacity);
    alpha = fadeAlphaAgainstSceneDepth(input.position, alpha);
    if (alpha < uniform.alphaCutoff) {
        discard;
    }
    let depth = particleViewDepth(particles[u32(input.color.w)]);
    alpha *= 1.0 - uniform.depthSoftness * smoothstep(2.0, 40.0, depth);
    output.color = vec4f(rgb, alpha);
    if (uniform.depthWrite > 0.5) {
        output.fragDepth = discSphereFragDepth(input.clipDepth, input.color.xy);
    }
    return output;
}

fn particleShadeRgb(p: Particle, cornerY: f32) -> vec3f {
    if (abs(uniform.motionMode - 3.0) < 0.5) {
        let along = cornerY * 0.5 + 0.5;
        let rnd = renderRand1(p.seed);
        let rnd2 = renderRand1(p.seed * 7.13);
        return renderCurveColor(
            rnd,
            rnd2,
            uniform.colorRandom,
            uniform.colorRandomBetween,
            along,
            uniform.colorEasing,
            uniform.colorKeyCount,
            uniform.colorKey0,
            uniform.colorKey1,
            uniform.colorKey2,
            uniform.colorKey3,
        );
    }
    return p.color;
}

@fragment
fn fragmentMain(input: FragmentInput) -> FragmentOutput {
    var output: FragmentOutput;
    let colorMapUv = input.color.xy * 0.5 + 0.5;
    let colorMapTex = textureSample(colorMap, colorMapSampler, colorMapUv);

#ifdef SHADOW_PASS
    if (input.shapeFlag > 0.5) {
        output.color = vec4f(input.clipDepth, 0.0, 0.0, 1.0);
        return output;
    }
    if (uniform.useColorMap > 0.5) {
        if (colorMapTex.a < uniform.alphaCutoff) {
            discard;
        }
    } else {
        let r2 = dot(input.color.xy, input.color.xy);
        if (r2 > 1.0) {
            discard;
        }
    }
    output.color = vec4f(input.clipDepth, 0.0, 0.0, 1.0);
    return output;
#else
    let p = particles[u32(input.color.w)];

    if (input.shapeFlag > 0.5) {
        var rgb = particleShadeRgb(p, 0.0);
        let normal = normalize(input.normalView);
        rgb *= particleLighting(normal, worldPosition);
        var alpha = input.color.z;
        let depth = particleViewDepth(p);
        alpha *= 1.0 - uniform.depthSoftness * smoothstep(2.0, 40.0, depth);
        output.color = vec4f(rgb, alpha);
        return output;
    }

    if (uniform.useColorMap > 0.5) {
        if (colorMapTex.a < uniform.alphaCutoff) {
            discard;
        }
        var rgb = particleShadeRgb(p, input.color.y);
        var alpha = colorMapTex.a * input.color.z;
        let normal = normalize(vec3f(input.color.xy, sqrt(max(1.0 - dot(input.color.xy, input.color.xy), 0.0))));
        rgb = mix(rgb, rgb * colorMapTex.rgb, uniform.colorMapMix);
        rgb *= particleLighting(normal, worldPosition);
        let depth = particleViewDepth(p);
        alpha *= 1.0 - uniform.depthSoftness * smoothstep(2.0, 40.0, depth);
        output.color = vec4f(rgb, alpha);
        return output;
    }

    let r2 = dot(input.color.xy, input.color.xy);
    if (r2 > 1.0) {
        discard;
    }
    let soft = 1.0 - r2;

    var rgb = particleShadeRgb(p, input.color.y);
    let normal = normalize(vec3f(input.color.xy, sqrt(max(1.0 - soft, 0.0))));
    rgb *= particleLighting(normal, worldPosition);
    return finalizeDiscFragment(input, rgb, soft, input.color.z);
#endif
}
